import type { BehavioralFacts } from "../../director/prompt/summarize.js";
import type { FloorManifest } from "../../schemas/manifest.js";
import type { PersonaName } from "../personas/types.js";

export const RESPONSIVENESS_METRIC_VERSION = "phase-42-responsiveness-v1" as const;

export type ResponsivenessDetectorProposalEntry = {
  readonly id: string;
  readonly persona: PersonaName;
  readonly description: string;
  /** Human review: detector encodes uncertain design judgment. */
  readonly uncertain?: boolean;
};

export type ResponsivenessDetector = ResponsivenessDetectorProposalEntry & {
  readonly detect: (
    manifest: FloorManifest,
    facts: BehavioralFacts,
  ) => boolean;
};

export type ResponsivenessDetectorHit = {
  readonly id: string;
  readonly hit: boolean;
};

export type ResponsivenessHitRate = {
  readonly metricVersion: typeof RESPONSIVENESS_METRIC_VERSION;
  readonly persona: PersonaName;
  readonly hits: number;
  readonly total: number;
  readonly rate: number;
  readonly detectors: readonly ResponsivenessDetectorHit[];
};

export type ResponsivenessMatrix = {
  readonly metricVersion: typeof RESPONSIVENESS_METRIC_VERSION;
  readonly sourcePersona: PersonaName;
  readonly samePersona: ResponsivenessHitRate;
  readonly crossPersona: Readonly<Record<PersonaName, ResponsivenessHitRate>>;
};

/** Trace shows hoarder-style play before manifest signals count. */
const hoarderTrace = (facts: BehavioralFacts): boolean =>
  facts.hoardingSignal >= 2 ||
  (facts.itemPickups > facts.itemUses && facts.combatEngagementRate <= 0.35);

/** Trace shows pacifist-style play before manifest signals count. */
const pacifistTrace = (facts: BehavioralFacts): boolean =>
  facts.fightsPicked === 0 &&
  facts.combatEngagementRate === 0 &&
  (facts.fightsAvoided > 0 || facts.retreatCount > 0);

/** Trace shows speedrunner-style play before manifest signals count. */
const speedrunnerTrace = (facts: BehavioralFacts): boolean =>
  facts.itemPickups <= 2 && facts.explorationRatio <= 0.14;

/** Trace shows completionist-style play before manifest signals count. */
const completionistTrace = (facts: BehavioralFacts): boolean =>
  facts.npcTalksInitiated > 0 || facts.cellsVisited >= 35;

/**
 * Trace shows chaotic, varied engagement (per-seed tolerance proxy).
 * Uses fact diversity because eval cells only receive BehavioralFacts.
 */
const chaosTrace = (facts: BehavioralFacts): boolean => {
  const itemCategoryUses = Object.keys(facts.itemUsesByCategory).length;
  return (
    (facts.fightsPicked > 0 && facts.fightsAvoided > 0) ||
    itemCategoryUses >= 2 ||
    (facts.closeCallCount > 0 && facts.questRefused > 0)
  );
};

const CAUTION_KEYWORDS = [
  "avoid",
  "careful",
  "caution",
  "quiet",
  "peace",
  "retreat",
  "still",
  "calm",
] as const;

const HOARD_KEYWORDS = [
  "hoard",
  "stash",
  "cache",
  "treasure",
  "stockpile",
  "burden",
  "weight",
] as const;

const PACE_KEYWORDS = [
  "stairs",
  "ascent",
  "exit",
  "swift",
  "hurry",
  "short",
  "direct",
] as const;

const QUEST_KEYWORDS = [
  "quest",
  "task",
  "errand",
  "promise",
  "ledger",
  "scribe",
] as const;

/**
 * Proposed detector set for orchestrator / human review at phase close.
 * Detectors marked uncertain encode design judgment that may need tuning.
 */
export const serializeDetectorProposal = (
  detectors: readonly ResponsivenessDetector[] = RESPONSIVENESS_DETECTOR_PROPOSAL,
): readonly ResponsivenessDetectorProposalEntry[] =>
  detectors.map(({ id, persona, description, uncertain }) => ({
    id,
    persona,
    description,
    ...(uncertain === undefined ? {} : { uncertain }),
  }));

export const RESPONSIVENESS_DETECTOR_PROPOSAL: readonly ResponsivenessDetector[] =
  [
    {
      id: "hoarder_item_density",
      persona: "hoarder",
      description:
        "Floor offers above-minimum item count or multiple coin pickups.",
      detect: (manifest, facts) =>
        hoarderTrace(facts) &&
        (manifest.items.length >= 5 ||
          manifest.items.filter((item) => item.kind === "coin").length >= 2),
    },
    {
      id: "hoarder_thief_pressure",
      persona: "hoarder",
      description: "Roster includes a thief behavior enemy.",
      detect: (manifest, facts) =>
        hoarderTrace(facts) &&
        manifest.roster.some((enemy) =>
          enemy.behaviors.some((behavior) => behavior.kind === "thief"),
        ),
    },
    {
      id: "hoarder_inventory_narration",
      persona: "hoarder",
      description: "Narration references hoarding or carrying burden.",
      uncertain: true,
      detect: (manifest, facts) =>
        hoarderTrace(facts) && narrationMatches(manifest, HOARD_KEYWORDS),
    },
    {
      id: "pacifist_open_routes",
      persona: "pacifist",
      description:
        "Layout flavor or room span suggests alternate routes (open/halls or wide room span).",
      detect: (manifest, facts) =>
        pacifistTrace(facts) &&
        (manifest.params.flavor === "open" ||
          manifest.params.flavor === "halls" ||
          manifest.params.roomCountRange.max -
            manifest.params.roomCountRange.min >=
            3),
    },
    {
      id: "pacifist_soft_threats",
      persona: "pacifist",
      description:
        "Few enemies are placed near the entrance; more keep-range/flee behaviors.",
      detect: (manifest, facts) => {
        if (!pacifistTrace(facts)) {
          return false;
        }

        const nearEntranceThreats = manifest.roster.filter(
          (enemy) => enemy.placementHint?.distance === "near_entrance",
        ).length;
        const avoidanceBehaviors = manifest.roster.filter((enemy) =>
          enemy.behaviors.some((behavior) =>
            behavior.kind === "keep_range" || behavior.kind === "flee_low_hp",
          ),
        ).length;
        return nearEntranceThreats <= 1 || avoidanceBehaviors >= 1;
      },
    },
    {
      id: "pacifist_caution_narration",
      persona: "pacifist",
      description: "Narration acknowledges caution or non-violence.",
      detect: (manifest, facts) =>
        pacifistTrace(facts) && narrationMatches(manifest, CAUTION_KEYWORDS),
    },
    {
      id: "speedrunner_compact_floor",
      persona: "speedrunner",
      description: "Compact room span or open/halls flavor for fast routing.",
      detect: (manifest, facts) =>
        speedrunnerTrace(facts) &&
        (manifest.params.roomCountRange.max <= 6 ||
          manifest.params.flavor === "open" ||
          manifest.params.flavor === "halls"),
    },
    {
      id: "speedrunner_near_entrance_loot",
      persona: "speedrunner",
      description: "High-value entities placed near entrance for grab-and-go.",
      detect: (manifest, facts) => {
        if (!speedrunnerTrace(facts)) {
          return false;
        }

        const nearEntranceEntities = [
          ...manifest.items,
          ...manifest.roster,
        ].filter((entry) => entry.placementHint?.distance === "near_entrance");
        return nearEntranceEntities.length >= 2;
      },
    },
    {
      id: "speedrunner_pace_narration",
      persona: "speedrunner",
      description: "Narration references stairs, exits, or urgency.",
      uncertain: true,
      detect: (manifest, facts) =>
        speedrunnerTrace(facts) && narrationMatches(manifest, PACE_KEYWORDS),
    },
    {
      id: "completionist_npc_present",
      persona: "completionist",
      description: "At least one NPC is authored on the floor.",
      detect: (manifest, facts) =>
        completionistTrace(facts) && manifest.npcs.length > 0,
    },
    {
      id: "completionist_quest_present",
      persona: "completionist",
      description: "A quest hook is present.",
      detect: (manifest, facts) =>
        completionistTrace(facts) && manifest.quest !== null,
    },
    {
      id: "completionist_rich_callbacks",
      persona: "completionist",
      description: "Multiple narration observations or callback tags.",
      detect: (manifest, facts) =>
        completionistTrace(facts) &&
        (manifest.narration.observations.length >= 2 ||
          manifest.metadata.callbacks.length >= 2 ||
          narrationMatches(manifest, QUEST_KEYWORDS)),
    },
    {
      id: "chaos_behavior_diversity",
      persona: "chaos",
      description: "Three or more distinct enemy behavior kinds.",
      detect: (manifest, facts) => {
        if (!chaosTrace(facts)) {
          return false;
        }

        const kinds = new Set(
          manifest.roster.flatMap((enemy) =>
            enemy.behaviors.map((behavior) => behavior.kind),
          ),
        );
        return kinds.size >= 3;
      },
    },
    {
      id: "chaos_trap_variety",
      persona: "chaos",
      description: "Multiple traps or mixed trap/item effect verbs.",
      uncertain: true,
      detect: (manifest, facts) =>
        chaosTrace(facts) &&
        (manifest.traps.length >= 2 ||
          new Set(
            manifest.traps.flatMap((trap) =>
              trap.effectBundle.effects.map((effect) => effect.kind),
            ),
          ).size >= 2),
    },
    {
      id: "chaos_mixed_origins",
      persona: "chaos",
      description: "Origin tag summary shows mixed made/old_stock/kept content.",
      detect: (manifest, facts) => {
        if (!chaosTrace(facts)) {
          return false;
        }

        const tags = manifest.metadata.originTags;
        const present = [
          tags.made > 0,
          tags.old_stock > 0,
          tags.kept > 0,
        ].filter(Boolean).length;
        return present >= 2;
      },
    },
    {
      id: "chaos_varied_engagement",
      persona: "chaos",
      description:
        "Trace shows mixed fight/avoid patterns and manifest offers diverse threats.",
      uncertain: true,
      detect: (manifest, facts) =>
        chaosTrace(facts) &&
        facts.fightsPicked > 0 &&
        facts.fightsAvoided > 0 &&
        manifest.roster.length >= 2,
    },
  ];

import { bounds } from "../../config/index.js";
import {
  getFallbackFloor,
  type FallbackContentPack,
} from "../../harness/content-loader.js";
import type {
  EnemyDefinition,
  ItemDefinition,
  TrapDefinition,
} from "../../schemas/entities/index.js";
import type { EffectBundle } from "../../schemas/vocab/index.js";
import type { FloorManifest } from "../../schemas/manifest.js";

export const NOVELTY_METRIC_VERSION = "phase-42-novelty-v1" as const;

/** Blended distance at or below this value flags near-duplicate content. */
export const NOVELTY_NEAR_DUPLICATE_THRESHOLD = 0.22;

export type NoveltyCorpus = {
  readonly fallbackPack: FallbackContentPack;
  readonly recentManifests: readonly FloorManifest[];
};

export type NoveltyComponents = {
  /** 0 = distinct names, 1 = corpus-identical naming. */
  readonly nameSimilarity: number;
  /** 0 = identical stat profiles, 1 = maximally different. */
  readonly statVectorDistance: number;
  /** 0 = disjoint composition, 1 = identical behavior/effect multiset. */
  readonly compositionOverlap: number;
};

export type NoveltyDistanceResult = {
  readonly metricVersion: typeof NOVELTY_METRIC_VERSION;
  readonly distance: number;
  /** Novelty score: equals distance (higher is fresher). */
  readonly score: number;
  readonly nearDuplicate: boolean;
  readonly components: NoveltyComponents;
  readonly vsFallback: NoveltyComponents;
  readonly vsRecent: NoveltyComponents | null;
};

const COMPONENT_WEIGHTS = {
  nameSimilarity: 0.35,
  statVectorDistance: 0.3,
  compositionOverlap: 0.35,
} as const;

export const distance = (
  manifest: FloorManifest,
  corpus: NoveltyCorpus,
): NoveltyDistanceResult => {
  const fallbackFloor = getFallbackFloor(corpus.fallbackPack, manifest.depth);
  const vsFallback = compareFeatureSets(
    extractManifestFeatures(manifest),
    extractFallbackFeatures(fallbackFloor),
  );
  const vsRecent =
    corpus.recentManifests.length === 0
      ? null
      : compareFeatureSets(
          extractManifestFeatures(manifest),
          mergeFeatureSets(
            corpus.recentManifests.map((recent) =>
              extractManifestFeatures(recent),
            ),
          ),
        );
  const blendedCorpus = mergeFeatureSets([
    extractFallbackFeatures(fallbackFloor),
    ...corpus.recentManifests.map((recent) => extractManifestFeatures(recent)),
  ]);
  const components = compareFeatureSets(
    extractManifestFeatures(manifest),
    blendedCorpus,
  );
  const corpusSimilarity = blendComponents(components);
  const recentSimilarity =
    vsRecent === null ? null : blendComponents(vsRecent);
  const distanceValue = clamp01(1 - corpusSimilarity);
  const score = distanceValue;

  return {
    metricVersion: NOVELTY_METRIC_VERSION,
    distance: distanceValue,
    score,
    nearDuplicate:
      corpusSimilarity >= 1 - NOVELTY_NEAR_DUPLICATE_THRESHOLD ||
      (recentSimilarity !== null &&
        recentSimilarity >= 1 - NOVELTY_NEAR_DUPLICATE_THRESHOLD),
    components,
    vsFallback,
    vsRecent,
  };
};

type ManifestFeatureSet = {
  readonly entityNames: readonly string[];
  readonly enemyStatVectors: readonly (readonly number[])[];
  readonly compositionTags: readonly string[];
};

const extractManifestFeatures = (manifest: FloorManifest): ManifestFeatureSet => ({
  entityNames: collectEntityNames(manifest),
  enemyStatVectors: manifest.roster.map((enemy) =>
    normalizeEnemyStats(enemy.stats.band, enemy.stats),
  ),
  compositionTags: [
    ...collectBehaviorTags(manifest.roster),
    ...manifest.items.flatMap((item) => collectItemEffectVerbs(item)),
    ...manifest.traps.flatMap((trap) => collectTrapEffectVerbs(trap)),
    ...manifest.roster.flatMap((enemy) =>
      enemy.abilities.flatMap((bundle) => collectBundleVerbs(bundle)),
    ),
  ],
});

const extractFallbackFeatures = (floor: {
  readonly roster: readonly EnemyDefinition[];
  readonly items: readonly ItemDefinition[];
  readonly traps: readonly TrapDefinition[];
}): ManifestFeatureSet => ({
  entityNames: [
    ...floor.roster.map((enemy) => enemy.name),
    ...floor.items.map((item) => item.name),
    ...floor.traps.map((trap) => trap.name),
  ],
  enemyStatVectors: floor.roster.map((enemy) =>
    normalizeEnemyStats(enemy.stats.band, enemy.stats),
  ),
  compositionTags: [
    ...floor.roster.flatMap((enemy) =>
      enemy.behaviors.map((behavior) => `behavior:${behavior.kind}`),
    ),
    ...floor.items.flatMap((item) => collectItemEffectVerbs(item)),
    ...floor.traps.flatMap((trap) => collectTrapEffectVerbs(trap)),
    ...floor.roster.flatMap((enemy) =>
      enemy.abilities.flatMap((bundle) => collectBundleVerbs(bundle)),
    ),
  ],
});

const mergeFeatureSets = (
  sets: readonly ManifestFeatureSet[],
): ManifestFeatureSet => ({
  entityNames: [...new Set(sets.flatMap((set) => set.entityNames))],
  enemyStatVectors: sets.flatMap((set) => set.enemyStatVectors),
  compositionTags: sets.flatMap((set) => set.compositionTags),
});

const compareFeatureSets = (
  manifest: ManifestFeatureSet,
  corpus: ManifestFeatureSet,
): NoveltyComponents => ({
  nameSimilarity: averageNameSimilarity(manifest.entityNames, corpus.entityNames),
  statVectorDistance: averageStatDistance(
    manifest.enemyStatVectors,
    corpus.enemyStatVectors,
  ),
  compositionOverlap: multisetJaccard(
    manifest.compositionTags,
    corpus.compositionTags,
  ),
});

const blendComponents = (components: NoveltyComponents): number =>
  clamp01(
    components.nameSimilarity * COMPONENT_WEIGHTS.nameSimilarity +
      (1 - components.statVectorDistance) * COMPONENT_WEIGHTS.statVectorDistance +
      components.compositionOverlap * COMPONENT_WEIGHTS.compositionOverlap,
  );

const collectEntityNames = (manifest: FloorManifest): readonly string[] => [
  ...manifest.roster.map((enemy) => normalizeName(enemy.name)),
  ...manifest.items.map((item) => normalizeName(item.name)),
  ...manifest.traps.map((trap) => normalizeName(trap.name)),
  ...manifest.npcs.map((npc) => normalizeName(npc.name)),
];

const collectBehaviorTags = (
  roster: FloorManifest["roster"],
): readonly string[] =>
  roster.flatMap((enemy) =>
    enemy.behaviors.map((behavior) => `behavior:${behavior.kind}`),
  );

const collectItemEffectVerbs = (item: ItemDefinition): readonly string[] => {
  const verbs: string[] = [`item:${item.kind}`];

  if (item.weapon?.onHit !== null && item.weapon?.onHit !== undefined) {
    verbs.push(...collectBundleVerbs(item.weapon.onHit.bundle));
  }
  if (item.armor?.onStruck !== null && item.armor?.onStruck !== undefined) {
    verbs.push(...collectBundleVerbs(item.armor.onStruck.bundle));
  }
  if (item.charm !== null) {
    verbs.push(...collectBundleVerbs(item.charm.passive));
  }
  if (item.draught !== null) {
    verbs.push(...collectBundleVerbs(item.draught.effect));
  }
  if (item.note !== null) {
    verbs.push(...collectBundleVerbs(item.note.effect));
  }
  if (item.throwable !== null) {
    verbs.push(...collectBundleVerbs(item.throwable.effect));
  }
  if (item.food !== null) {
    verbs.push(...collectBundleVerbs(item.food.effect));
  }
  if (item.tool !== null) {
    verbs.push(...collectBundleVerbs(item.tool.effect));
  }

  return verbs;
};

const collectTrapEffectVerbs = (trap: TrapDefinition): readonly string[] => [
  "trap:step",
  ...collectBundleVerbs(trap.effectBundle),
];

const collectBundleVerbs = (bundle: EffectBundle): readonly string[] =>
  bundle.effects.map((effect) => `effect:${effect.kind}`);

const normalizeName = (name: string): string => name.trim().toLowerCase();

const averageNameSimilarity = (
  manifestNames: readonly string[],
  corpusNames: readonly string[],
): number => {
  if (manifestNames.length === 0 || corpusNames.length === 0) {
    return 0;
  }

  const similarities = manifestNames.map((name) => {
    const best = Math.max(
      ...corpusNames.map((corpusName) => normalizedEditSimilarity(name, corpusName)),
    );
    return best;
  });

  return mean(similarities);
};

const normalizedEditSimilarity = (left: string, right: string): number => {
  if (left === right) {
    return 1;
  }

  const maxLength = Math.max(left.length, right.length, 1);
  return 1 - levenshteinDistance(left, right) / maxLength;
};

const levenshteinDistance = (left: string, right: string): number => {
  const rows = left.length + 1;
  const cols = right.length + 1;
  const matrix: number[][] = Array.from({ length: rows }, () =>
