    })),
    narration: {
      floorIntro: "A new draft of stone waits under unfamiliar lamps.",
      observations: [
        {
          id: "fresh-obs",
          triggerTag: "fresh-room",
          text: "Nothing here remembers the fallback stock.",
        },
      ],
    },
    metadata: {
      ...base.metadata,
      callbacks: ["fresh-room"],
    },
