const compareRate = (
  segment: string,
  metric: RateMetric,
  baseline: EvalRate,
  candidate: EvalRate,
): EvalComparisonRow => {
  const delta = candidate.percent - baseline.percent;
  const regression =
    metric === "fallback" ? delta > 0 : delta < 0;

  return {
    segment,
    metric,
    unit: "percent",
    baseline: baseline.percent,
    candidate: candidate.percent,
    delta,
    regression,
  };
};

const compareLatency = (
  segment: string,
  metric: string,
  baseline: number,
  candidate: number,
): EvalComparisonRow => {
  const delta = candidate - baseline;

  return {
    segment,
    metric,
    unit: "ms",
    baseline,
    candidate,
    delta,
    regression: delta > 0,
  };
};

