 57	  const recentFeatureSets = corpus.recentManifests.map((recent) =>
 58	    extractManifestFeatures(recent),
 59	  );
 60	  const vsFallback = bestCorpusMatch(manifestFeatures, fallbackFeatureSets);
 61	  const vsRecent =
 62	    recentFeatureSets.length === 0
 63	      ? null
 64	      : bestCorpusMatch(manifestFeatures, recentFeatureSets);
 65	  const components = bestCorpusMatch(manifestFeatures, [
 66	    ...fallbackFeatureSets,
 67	    ...recentFeatureSets,
 68	  ]);
 69	  const corpusSimilarity = blendComponents(components);
 70	  const recentSimilarity =
 71	    vsRecent === null ? null : blendComponents(vsRecent);
 72	  const distanceValue = clamp01(1 - corpusSimilarity);
 73	  const score = distanceValue;
 74	
 75	  return {
 76	    metricVersion: NOVELTY_METRIC_VERSION,
 77	    distance: distanceValue,
 78	    score,
 79	    nearDuplicate:
 80	      corpusSimilarity >= 1 - NOVELTY_NEAR_DUPLICATE_THRESHOLD ||
 81	      (recentSimilarity !== null &&
 82	        recentSimilarity >= 1 - NOVELTY_NEAR_DUPLICATE_THRESHOLD),
 83	    components,
 84	    vsFallback,
 85	    vsRecent,
 86	  };
 87	};
