 89	type ManifestFeatureSet = {
 90	  readonly entityNames: readonly string[];
 91	  readonly enemyStatVectors: readonly (readonly number[])[];
 92	  readonly compositionTags: readonly string[];
 93	};
 94	
 95	const extractFallbackPackFeatures = (
 96	  pack: FallbackContentPack,
 97	): readonly ManifestFeatureSet[] =>
 98	  [...pack.floors.keys()]
 99	    .sort((left, right) => left - right)
100	    .map((depth) => extractFallbackFeatures(getFallbackFloor(pack, depth)));
101	
102	const extractManifestFeatures = (manifest: FloorManifest): ManifestFeatureSet => ({
103	  entityNames: collectEntityNames(manifest),
104	  enemyStatVectors: manifest.roster.map((enemy) =>
105	    normalizeEnemyStats(enemy.stats.band, enemy.stats),
106	  ),
107	  compositionTags: [
108	    ...collectBehaviorTags(manifest.roster),
109	    ...manifest.items.flatMap((item) => collectItemEffectVerbs(item)),
110	    ...manifest.traps.flatMap((trap) => collectTrapEffectVerbs(trap)),
111	    ...manifest.roster.flatMap((enemy) =>
112	      enemy.abilities.flatMap((bundle) => collectBundleVerbs(bundle)),
113	    ),
114	  ],
115	});
116	
117	const extractFallbackFeatures = (floor: {
118	  readonly roster: readonly EnemyDefinition[];
119	  readonly items: readonly ItemDefinition[];
120	  readonly traps: readonly TrapDefinition[];
121	  readonly npcs: readonly NpcDefinition[];
122	}): ManifestFeatureSet => ({
123	  entityNames: [
124	    ...floor.roster.map((enemy) => normalizeName(enemy.name)),
125	    ...floor.items.map((item) => normalizeName(item.name)),
126	    ...floor.traps.map((trap) => normalizeName(trap.name)),
127	    ...floor.npcs.map((npc) => normalizeName(npc.name)),
128	  ],
129	  enemyStatVectors: floor.roster.map((enemy) =>
130	    normalizeEnemyStats(enemy.stats.band, enemy.stats),
131	  ),
132	  compositionTags: [
133	    ...floor.roster.flatMap((enemy) =>
134	      enemy.behaviors.map((behavior) => `behavior:${behavior.kind}`),
135	    ),
136	    ...floor.items.flatMap((item) => collectItemEffectVerbs(item)),
137	    ...floor.traps.flatMap((trap) => collectTrapEffectVerbs(trap)),
138	    ...floor.roster.flatMap((enemy) =>
139	      enemy.abilities.flatMap((bundle) => collectBundleVerbs(bundle)),
140	    ),
141	  ],
142	});
143	
144	const compareFeatureSets = (
145	  manifest: ManifestFeatureSet,
146	  corpus: ManifestFeatureSet,
147	): NoveltyComponents => ({
148	  nameSimilarity: averageNameSimilarity(manifest.entityNames, corpus.entityNames),
149	  statVectorDistance: averageStatDistance(
150	    manifest.enemyStatVectors,
151	    corpus.enemyStatVectors,
152	  ),
153	  compositionOverlap: multisetJaccard(
154	    manifest.compositionTags,
155	    corpus.compositionTags,
156	  ),
157	});
158	
159	const bestCorpusMatch = (
160	  manifest: ManifestFeatureSet,
161	  corpus: readonly ManifestFeatureSet[],
162	): NoveltyComponents => {
163	  const candidates =
164	    corpus.length === 0
165	      ? [
166	          {
167	            entityNames: [],
168	            enemyStatVectors: [],
169	            compositionTags: [],
170	          },
171	        ]
172	      : corpus;
173	
174	  return candidates
175	    .map((candidate) => compareFeatureSets(manifest, candidate))
176	    .reduce((best, current) =>
177	      blendComponents(current) > blendComponents(best) ? current : best,
178	    );
179	};
180	
181	const blendComponents = (components: NoveltyComponents): number =>
182	  clamp01(
183	    components.nameSimilarity * COMPONENT_WEIGHTS.nameSimilarity +
184	      (1 - components.statVectorDistance) * COMPONENT_WEIGHTS.statVectorDistance +
185	      components.compositionOverlap * COMPONENT_WEIGHTS.compositionOverlap,
186	  );
187	
188	const collectEntityNames = (manifest: FloorManifest): readonly string[] => [
189	  ...manifest.roster.map((enemy) => normalizeName(enemy.name)),
190	  ...manifest.items.map((item) => normalizeName(item.name)),
191	  ...manifest.traps.map((trap) => normalizeName(trap.name)),
192	  ...manifest.npcs.map((npc) => normalizeName(npc.name)),
193	];
194	
195	const collectBehaviorTags = (
196	  roster: FloorManifest["roster"],
197	): readonly string[] =>
198	  roster.flatMap((enemy) =>
199	    enemy.behaviors.map((behavior) => `behavior:${behavior.kind}`),
200	  );
201	
202	const collectItemEffectVerbs = (item: ItemDefinition): readonly string[] => {
203	  const verbs: string[] = [`item:${item.kind}`];
204	
205	  if (item.weapon?.onHit !== null && item.weapon?.onHit !== undefined) {
206	    verbs.push(...collectBundleVerbs(item.weapon.onHit.bundle));
207	  }
208	  if (item.armor?.onStruck !== null && item.armor?.onStruck !== undefined) {
209	    verbs.push(...collectBundleVerbs(item.armor.onStruck.bundle));
210	  }
211	  if (item.charm !== null) {
212	    verbs.push(...collectBundleVerbs(item.charm.passive));
213	  }
214	  if (item.draught !== null) {
215	    verbs.push(...collectBundleVerbs(item.draught.effect));
216	  }
217	  if (item.note !== null) {
218	    verbs.push(...collectBundleVerbs(item.note.effect));
219	  }
220	  if (item.throwable !== null) {
221	    verbs.push(...collectBundleVerbs(item.throwable.effect));
222	  }
223	  if (item.food !== null) {
224	    verbs.push(...collectBundleVerbs(item.food.effect));
225	  }
226	  if (item.tool !== null) {
227	    verbs.push(...collectBundleVerbs(item.tool.effect));
228	  }
229	
230	  return verbs;
231	};
232	
233	const collectTrapEffectVerbs = (trap: TrapDefinition): readonly string[] => [
234	  "trap:step",
235	  ...collectBundleVerbs(trap.effectBundle),
236	];
237	
238	const collectBundleVerbs = (bundle: EffectBundle): readonly string[] =>
239	  bundle.effects.map((effect) => `effect:${effect.kind}`);
