362	          ? 0
363	          : noveltyScores.reduce((sum, score) => sum + score, 0) /
364	            noveltyScores.length,
365	      nearDuplicateCount,
366	      sampleCount: summaries.reduce(
367	        (sum, summary) => sum + summary.novelty.sampleCount,
